import javax.persistence.*;   //For JPA/Hibernet operations (ORM) and related packages like SessionFactory, EntityManager...etc are used here..   
                         
@Entity                     //This marks a class java_45085_SessionManager_A07 an entity which will be mapped to the database table ie., UserDetails in this case. 
public class Employee {         //In real application it would also have many more properties and methods like getter,setters etc...  
	 @Id                    //The annotation id indicates primary key of a particular column or field which has unique identifier (Primary Key) for each record inside the table   
     private int empid;        //Example property. In real application this would be generated by database automatically and also might have getter, setters...  
     
	 @Column(name="emp_Name")  //This annotation is used to specify column in Database Table for a particular field (in our case "employee name"), if different from the variable then use it.   
     private String empname;          //Example property, again same as above  
}                             
     
